SAML_REQUEST_TEMPLATE = '''<?xml version="1.0" encoding="UTF-8"?>
<samlp:AuthnRequest xmlns:samlp="urn:oasis:names:tc:SAML:2.0:protocol"
                    xmlns:saml="urn:oasis:names:tc:SAML:2.0:assertion"
                    ID="{request_id}"
                    Version="2.0"
                    IssueInstant="{issue_instant}"
                    Destination="{idp_sso_url}"
                    AssertionConsumerServiceURL="{acs_url}"
                    ProtocolBinding="urn:oasis:names:tc:SAML:2.0:bindings:HTTP-POST">
    <saml:Issuer>{sp_entity_id}</saml:Issuer>
    <samlp:NameIDPolicy Format="urn:oasis:names:tc:SAML:1.1:nameid-format:emailAddress"
                        AllowCreate="true"/>
</samlp:AuthnRequest>
'''

def generate_saml_request():
    request_id = '_' + str(uuid.uuid4())
    issue_instant = datetime.utcnow().strftime('%Y-%m-%dT%H:%M:%SZ')
    
    saml_request = SAML_REQUEST_TEMPLATE.format(
        request_id=request_id,
        issue_instant=issue_instant,
        idp_sso_url=IDP_SSO_URL,
        acs_url=SP_ACS_URL,
        sp_entity_id=SP_ENTITY_ID
    )
    
    pending_requests[request_id] = {
        'timestamp': datetime.utcnow(),
        'id': request_id
    }
    
    encoded_request = base64.b64encode(saml_request.encode('utf-8')).decode('utf-8')
    return encoded_request, request_id

def parse_saml_response(saml_response_b64):
    try:
        saml_response_xml = base64.b64decode(saml_response_b64)
        root = ET.fromstring(saml_response_xml)
        
        return root
    except Exception as e:
        raise ValueError(f"Failed to parse SAML response: {str(e)}")

def extract_assertion(response_root):
    assertion = response_root.find('.//saml:Assertion', SAML_NAMESPACES)
    
    if assertion is None:
        raise ValueError("No Assertion found in SAML response")
    
    return assertion

def validate_assertion(assertion):
    subject = assertion.find('.//saml:Subject', SAML_NAMESPACES)
    if subject is None:
        raise ValueError("Assertion missing Subject element")
    
    conditions = assertion.find('.//saml:Conditions', SAML_NAMESPACES)
    if conditions is not None:
        not_before = conditions.get('NotBefore')
        not_on_or_after = conditions.get('NotOnOrAfter')
        
        if not_before:
            not_before_dt = datetime.strptime(not_before, '%Y-%m-%dT%H:%M:%SZ')
            if datetime.utcnow() < not_before_dt:
                raise ValueError("Assertion not yet valid")
        
        if not_on_or_after:
            not_on_or_after_dt = datetime.strptime(not_on_or_after, '%Y-%m-%dT%H:%M:%SZ')
            if datetime.utcnow() >= not_on_or_after_dt:
                raise ValueError("Assertion has expired")
    
    return True

def extract_user_attributes(assertion):
    attributes = {}
    
    name_id = assertion.find('.//saml:Subject/saml:NameID', SAML_NAMESPACES)
    if name_id is not None:
        attributes['NameID'] = name_id.text
        attributes['NameIDFormat'] = name_id.get('Format', '')
    
    attribute_statements = assertion.findall('.//saml:AttributeStatement/saml:Attribute', SAML_NAMESPACES)
    
    for attr in attribute_statements:
        attr_name = attr.get('Name')
        attr_values = attr.findall('saml:AttributeValue', SAML_NAMESPACES)
        
        if len(attr_values) == 1:
            attributes[attr_name] = attr_values[0].text
        elif len(attr_values) > 1:
            attributes[attr_name] = [av.text for av in attr_values]
    
    return attributes

def create_user_session(user_attributes):
    session.permanent = True
    session['authenticated'] = True
    session['user_id'] = user_attributes.get('NameID', 'unknown')
    session['attributes'] = user_attributes
    session['login_time'] = datetime.utcnow().isoformat()
    session['session_id'] = str(uuid.uuid4())

@app.route('/')
def index():
    user = session.get('user_id')
    attributes = session.get('attributes', {})
    status = 'Authenticated' if session.get('authenticated') else 'Not Authenticated'
    
    return render_template_string(LOGIN_PAGE, user=user, attributes=attributes, status=status)

@app.route('/saml/login', methods=['POST'])
def saml_login():
    saml_request, request_id = generate_saml_request()
    
    redirect_url = f"{IDP_SSO_URL}?SAMLRequest={saml_request}"
    
    return redirect(redirect_url)

@app.route('/saml/acs', methods=['POST'])
def assertion_consumer_service():
    try:
        saml_response_b64 = request.form.get('SAMLResponse')
        
        if not saml_response_b64:
            return jsonify({'error': 'No SAMLResponse in request'}), 400
        
        response_root = parse_saml_response(saml_response_b64)
        
        status_code = response_root.find('.//samlp:StatusCode', SAML_NAMESPACES)
        if status_code is not None:
            status_value = status_code.get('Value', '')
            if 'Success' not in status_value:
                return jsonify({'error': f'SAML authentication failed: {status_value}'}), 400
        
        assertion = extract_assertion(response_root)
        
        validate_assertion(assertion)
        
        user_attributes = extract_user_attributes(assertion)
        
        if not user_attributes:
            return jsonify({'error': 'No user attributes found in assertion'}), 400
        
        create_user_session(user_attributes)
        
        return redirect(url_for('index'))
        
    except ValueError as e:
        return jsonify({'error': str(e)}), 400
    except Exception as e:
        return jsonify({'error': f'Unexpected error: {str(e)}'}), 500

@app.route('/saml/logout', methods=['POST'])
def saml_logout():
    session.clear()
    return redirect(url_for('index'))

@app.route('/saml/metadata')
def metadata():
    metadata_xml = f'''<?xml version="1.0" encoding="UTF-8"?>
<md:EntityDescriptor xmlns:md="urn:oasis:names:tc:SAML:2.0:metadata"
                     entityID="{SP_ENTITY_ID}">
    <md:SPSSODescriptor protocolSupportEnumeration="urn:oasis:names:tc:SAML:2.0:protocol">
        <md:AssertionConsumerService Binding="urn:oasis:names:tc:SAML:2.0:bindings:HTTP-POST"
                                     Location="{SP_ACS_URL}"
                                     index="0"/>
    </md:SPSSODescriptor>
</md:EntityDescriptor>
'''
    return metadata_xml, 200, {'Content-Type': 'application/xml'}

@app.route('/api/session')
def get_session():
    if session.get('authenticated'):
        return jsonify({
            'authenticated': True,
            'user_id': session.get('user_id'),
            'attributes': session.get('attributes'),
            'login_time': session.get('login_time'),
            'session_id': session.get('session_id')
        })
    else:
        return jsonify({'authenticated': False})

